parameters.jsCode:
const alerts = $input.all().map(i => i.json);

const facts = alerts.slice(0, 10).map((a, i) => ({
  title: `${i + 1}. ${a.display_name}`,
  value: `${a.alertname} | ${Math.floor(a.hours_elapsed)}시간 경과 | 역할: ${a.instance_role || '-'}`
}));

const alertIds = alerts.map(a => a.id);

return [{
  json: {
    alertIds,
    count: alerts.length,
    card: {
      type: 'message',
      attachments: [{
        contentType: 'application/vnd.microsoft.card.adaptive',
        content: {
          type: 'AdaptiveCard',
          version: '1.4',
          body: [
            {
              type: 'TextBlock',
              text: `🚨 미처리 Critical 알림 에스컬레이션 (${alerts.length}건)`,
              weight: 'Bolder',
              size: 'Medium',
              color: 'Attention'
            },
            {
              type: 'TextBlock',
              text: '2시간 이상 미처리된 Critical 알림이 있습니다. 즉시 확인하세요.',
              wrap: true
            },
            {
              type: 'FactSet',
              facts
            }
          ],
          actions: [{
            type: 'Action.OpenUrl',
            title: '알림 목록 확인',
            url: `${ $env?.ADMIN_API_URL?.replace(':8080', '') || 'http://localhost' }:5678`
          }]
        }
      }]
    }
  }
}];

